  ('medical-tech-moex-20588', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '主動脈瓣 (aortic valve) 關閉，發生在心臟週期之何時期？ 等容心室收縮期 (isovolumetric ventricular contraction)  心室射血期 (ventricular ejection) 等容心室舒張期 (isovolumetric ventricular relaxation)  心室充血期 (ventricular filling)', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20589', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '林老太太患有心雜音，經診斷後發現其左心房室瓣膜狹窄。則她最有可能有下列何種情況？ 心室收縮時出現雜音 (systolic murmur)  心室舒張時出現雜音 (diastolic murmur) 左心室於收縮期壓力高於正常人  左心室於舒張期壓力高於正常人', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20590', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '下列有關體循環及肺循環之敘述，何者正確？ 肺動脈壓大於體循環動脈壓  肺動脈阻力大於體循環動脈阻力 肺動脈所含瓣膜少於體循環動脈所含瓣膜  肺動脈含氧量低於體循環動脈含氧量', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20591', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '失血後，下列那些參數會較未失血前增加？ 心跳  心搏量 (stroke volume)  心輸出量 (cardiac output) 週邊血管總阻力 (total peripheral resistance)  交感神經活動頻率  靜脈張力 (venous tone)', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20592', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '某病人因疲倦、呼吸短促、腿踝浮腫而就醫，經檢查顯示其心室肥大而且心輸出量 (cardiac output) 偏低。 則下列何種治療最有助於病人？ 補充生理食鹽水以增加心輸出量  注射鈣離子阻斷劑以減少心臟負荷 注射毛地黃 (digitalis) 以促進心臟收縮  注射硝化甘油 (nitroglycerin) 以促進心臟收縮', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20593', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '甲先生的動脈壓為120/80 mmHg。則下列何者最正確？ 他的平均動脈壓為 100 mmHg  他的平均動脈壓為 93 mmHg 他的脈搏壓 (pulse pressure) 為 100 mmHg  他的心臟收縮壓為 80 mmHg', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20594', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '下列有關血管張力素 (angiotensin II) 之敘述，何者錯誤？ Angiotensin II促進血管收縮而升高血壓 Angiotensin II促進體液保留而升高血壓 血管張力素轉化酵素 (angiotensin converting enzyme) 抑制劑可直接阻止angiotensin II作用 血管張力素轉化酵素促進angiotensin I分解成angiotensin II', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20595', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '身體因低氧 (hypoxia) 而增加通氣量的呼吸反射中，最主要的感覺神經受器位於何處？ 中樞化學感受器 (central chemoreceptors)  頸動脈體化學感受器 (carotid body chemoreceptors) 主動脈體化學感受器 (aortic body chemoreceptors)  肺迷走神經化學感受器 (lung vagal chemoreceptors)', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20596', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '病人因嘔吐多次可能導致下列何種中毒？ 呼吸性酸中毒 (respiratory acidosis)  呼吸性鹼中毒 (respiratory alkalosis) 代謝性酸中毒 (metabolic acidosis)  代謝性鹼中毒 (metabolic alkalosis)', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20597', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '肺泡細胞的功能是氣體交換及釋放表面張力素 (surfactant)，這兩種功能各是由那一型肺泡細胞負責的？ 皆由第一型細胞負責 皆由第二型細胞負責 氣體交換由第一型細胞負責，釋放表面張力素由第二型細胞負責 氣體交換由第二型細胞負責，釋放表面張力素由第一型細胞負責', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
